import { GeoBubbleSeries } from '../geo-bubble/geo-bubble';
import { inherit } from '../utils/zcutils';
import { maps } from '../core/chart-instance-manager';

/**
 *
 * @param series
 * @param geoMap
 * @param index
 * @constructor
 */
export function GeoBubblePieSeries(series, geoMap, index) {
    GeoBubbleSeries.call(this, series, geoMap, index);
}

// inherit from MapSeries
inherit(GeoBubblePieSeries, GeoBubbleSeries);

// add HeatMapSeries to global holder
maps.GeoMap.SeriesTypes.set('geobubblepie', GeoBubblePieSeries);
